document.addEventListener("DOMContentLoaded",function(){const e=document.querySelectorAll(".one-service-one-FAQ");let n=1;const t=Math.ceil(e.length/6);!function o(c){e.forEach(e=>e.style.display="none");const l=6*(c-1),d=l+6;for(let n=l;n<d&&n<e.length;n++)e[n].style.display="block";const i=document.getElementById("pagination");i.innerHTML="";for(let e=1;e<=t;e++){const t=document.createElement("button");t.innerText=e,t.addEventListener("click",()=>{n=e,o(n)}),i.appendChild(t)}}(n)});